SELECT city_id, median_monthly_salary, median_weekly_salary
FROM city_salaries
ORDER BY median_monthly_salary DESC, median_weekly_salary DESC;

SELECT industry_id, AVG(median_annual_salary) AS avg_median_salary
FROM city_salaries
GROUP BY industry_id;

SELECT *
FROM city_salaries
WHERE city_id IN (SELECT city_id FROM cities WHERE state_id = 1);

SELECT COUNT(*) AS Total_Records_With_City_Name_In_Version
FROM city_salaries
WHERE version LIKE '%city_name%';
